script.text:
      /* <flatten type="Javascript"> */
function initUnitSite(f) {
  var o = f.getItem('ma_nh');
  o.field.AllowNulls = (f._siteMethod != 1);
  if (!o.field.AllowNulls) {
    var grandNode = o.parentNode.parentNode;
    Sys.UI.DomElement.addCssClass(grandNode, 'Required');
    Sys.UI.DomElement.addCssClass(grandNode, $func.replace(f._id, '.', '_'));
  }
  if (f._action == 'New') {
    o = f.getItem('ma_dvcs');
    o.value = f._unitCode;
    f.getItem('ten_dvcs%l').value = f._unitName;
    f.live(o);
  }
}
function active$FormSite(f) {f.add_onResponseComplete(on$FormSite$ResponseComplete);}
function close$FormSite(f) {try {f.remove_onResponseComplete(on$FormSite$ResponseComplete)} catch (ex) {}}
function on$FormSite$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_kho');
      break;
    default:
      break;
  }
}
/* </flatten> */
      &ScriptIrregular;
